  1→import { useCallback, useState } from 'react';
  2→import { NavViewData, TRAY_COMMAND_MAP } from './app_types';
  3→import { ActionPanel } from './components/action_panel/action_panel';
  4→import { CommandPalette } from './components/command_palette/command_palette';
  5→import { DetailItemView } from './components/detail/detail_item_view';
  6→import { Kbd } from './components/kbd/kbd';
  7→import { RootSearchView } from './components/root_search/root_search_view';
  8→import { SearchBar } from './components/search_bar/search_bar';
  9→import {
 10→  NavigationContextProvider,
 11→  useNavigationStack,
 12→} from './hooks/use_navigation';
 13→import { useRecentCommands } from './hooks/use_recent_commands';
 14→import { useTheme } from './hooks/use_theme';
 15→import { useWindow } from './hooks/use_window';
 16→import { getCommand } from './registry';
 17→
 18→function renderNavView(data: NavViewData) {
 19→  if (data.type === 'command') {
 20→    const cmd = getCommand(data.commandId);
 21→    if (cmd?.component) {
 22→      const Component = cmd.component;
 23→      return <Component />;
 24→    }
 25→    return null;
 26→  }
 27→
 28→  if (data.type === 'detail') {
 29→    return <DetailItemView item={data.item} />;
 30→  }
 31→
 32→  return null;
 33→}
 34→
 35→export function App() {
 36→  useTheme();
 37→  const nav = useNavigationStack<NavViewData>('Raycast');
 38→  const { push, popToRoot } = nav;
 39→  const { addRecent } = useRecentCommands();
 40→  const [isCompact, setIsCompact] = useState(true);
 41→
 42→  const handleTrayNavigate = useCallback(
 43→    (target: string) => {
 44→      const mapping = TRAY_COMMAND_MAP[target];
 45→      if (!mapping) return;
 46→
 47→      const cmd = getCommand(mapping.id);
 48→      if (!cmd?.component) return;
 49→
 50→      popToRoot();
 51→      addRecent(mapping.id);
 52→      push(mapping.name, {
 53→        type: 'command',
 54→        commandId: mapping.id,
 55→      });
 56→    },
 57→    [
 58→      push,
 59→      popToRoot,
 60→      addRecent,
 61→    ],
 62→  );
 63→
 64→  useWindow({
 65→    onShow: () => {
 66→      const input =
 67→        document.querySelector<HTMLInputElement>('.search-bar__input');
 68→      input?.focus();
 69→    },
 70→    onHide: () => {
 71→      popToRoot();
 72→    },
 73→    onTrayNavigate: handleTrayNavigate,
 74→  });
 75→
 76→  const currentNavData = nav.currentEntry?.data;
 77→  const isFullView =
 78→    currentNavData?.type === 'command' &&
 79→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 80→
 81→  const navDirectionClass =
 82→    nav.direction === 'push'
 83→      ? ' command-palette__nav-view--push'
 84→      : nav.direction === 'pop'
 85→        ? ' command-palette__nav-view--pop'
 86→        : '';
 87→
 88→  const isRoot = !currentNavData;
 89→  const compact = isRoot && isCompact;
 90→
 91→  const contextLabel =
 92→    nav.breadcrumbs.length > 0
 93→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
 94→      : 'Raycast';
 95→
 96→  return (
 97→    <NavigationContextProvider value={nav}>
 98→      <CommandPalette isLoading compact={compact}>
 99→        {isFullView && nav.currentEntry ? (
100→          <div
101→            key={nav.navKey}
102→            className={`command-palette__nav-view${navDirectionClass}`}
103→          >
104→            {renderNavView(nav.currentEntry.data)}
105→          </div>
106→        ) : nav.currentEntry ? (
107→          <>
108→            <SearchBar
109→              value=""
110→              onChange={() => {}}
111→              breadcrumbs={
112→                nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
113→              }
114→            />
115→            <div
116→              key={nav.navKey}
117→              className={`command-palette__nav-view${navDirectionClass}`}
118→            >
119→              <div className="command-palette__body">
120→                <div className="command-palette__list-container">
121→                  {renderNavView(nav.currentEntry.data)}
122→                </div>
123→              </div>
124→            </div>
125→            <ActionPanel
126→              contextLabel={contextLabel}
127→              actions={[
128→                {
129→                  label: 'Open',
130→                  shortcut: <Kbd keys={['↵']} />,
131→                },
132→              ]}
133→              dropdownOpen={false}
134→              dropdownSections={[]}
135→              onDropdownClose={() => {}}
136→            />
137→          </>
138→        ) : (
139→          <RootSearchView onCompactChange={setIsCompact} />
140→        )}
141→      </CommandPalette>
142→    </NavigationContextProvider>
143→  );
144→}
