 1→import type { ListItemData } from './types';
 2→
 3→export type NavViewData =
 4→  | {
 5→      type: 'command';
 6→      commandId: string;
 7→    }
 8→  | {
 9→      type: 'detail';
10→      item: ListItemData;
11→    };
12→
