14→  string,
15→  {
16→    id: string;
17→    name: string;
18→  }
19→> = {
20→  clipboard: {
21→    id: 'clipboard-history',
22→    name: 'Clipboard History',
23→  },
24→  snippets: {
25→    id: 'snippets',
26→    name: 'Snippets',
27→  },
28→  settings: {
29→    id: 'settings',
30→    name: 'Settings',
31→  },
32→  about: {
33→    id: 'settings',
34→    name: 'Settings',
35→  },
36→  'check-updates': {
37→    id: 'settings',
38→    name: 'Settings',
39→  },
40→};
