  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import type { NavViewData } from '../../app_types';
  3→import { useAlert } from '../../hooks/use_alert';
  4→import { useFavorites } from '../../hooks/use_favorites';
  5→import { useHUD } from '../../hooks/use_hud';
  6→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
  7→import { useNavigation } from '../../hooks/use_navigation';
  8→import { useRecentCommands } from '../../hooks/use_recent_commands';
  9→import { useToast } from '../../hooks/use_toast';
 10→import { getCommand, getSections, searchCommands } from '../../registry';
 11→import type { ListItemData, SectionData } from '../../types';
 12→import { evaluate } from '../../utils/calculator';
 13→import { fuzzyMatch } from '../../utils/fuzzy_search';
 14→import { ActionPanel } from '../action_panel/action_panel';
 15→import {
 16→  ClipboardHUDIcon,
 17→  createCopyAction,
 18→  performCopy,
 19→} from '../action_panel/actions';
 20→import { Alert } from '../alert/alert';
 21→import { Detail } from '../detail/detail';
 22→import { DetailMetadata } from '../detail/detail_metadata';
 23→import { renderMetadataEntry } from '../detail/render_metadata';
 24→import { EmptyState } from '../empty_state/empty_state';
 25→import { HUDContainer } from '../hud/hud_container';
 26→import { CalculatorIcon, MagnifyingGlassIcon, StarFilledIcon } from '../icons';
 27→import { Kbd } from '../kbd/kbd';
 28→import { List, ListItem, ListSection } from '../list';
 29→import { QuickLook } from '../quick_look/quick_look';
 30→import { SearchBar } from '../search_bar/search_bar';
 31→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 32→import { SearchDropdown } from '../search_bar/search_dropdown';
 33→import { ToastContainer } from '../toast/toast_container';
 34→
 35→function flattenItems(sections: SectionData[]): ListItemData[] {
 36→  return sections.flatMap(s => s.items);
 37→}
 38→
 39→const searchFilterSections: SearchDropdownSection[] = [
 40→  {
 41→    options: [
 42→      {
 43→        label: 'All',
 44→        value: 'all',
 45→      },
 46→    ],
 47→  },
 48→  {
 49→    title: 'Types',
 50→    options: [
 51→      {
 52→        label: 'Commands',
 53→        value: 'commands',
 54→      },
 55→      {
 56→        label: 'Applications',
 57→        value: 'applications',
 58→      },
 59→    ],
 60→  },
 61→];
 62→
 63→interface RootSearchViewProps {
 64→  onCompactChange?: (compact: boolean) => void;
 65→}
 66→
 67→export function RootSearchView({ onCompactChange }: RootSearchViewProps) {
 68→  const nav = useNavigation<NavViewData>();
 69→  const { push } = nav;
 70→
 71→  const [query, setQuery] = useState('');
 72→  const [filterValue, setFilterValue] = useState('all');
 73→  const [selectedIndex, setSelectedIndex] = useState(0);
 74→  const [actionsOpen, setActionsOpen] = useState(false);
 75→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 76→
 77→  const { toasts, show: showToast, hide: hideToast } = useToast();
 78→  const { items: hudItems, show: showHUD } = useHUD();
 79→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 80→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 81→    useFavorites();
 82→  const { recentIds, addRecent } = useRecentCommands();
 83→
 84→  useEffect(() => {
 85→    if (nav.stackDepth === 0) {
 86→      setQuery('');
 87→      setFilterValue('all');
 88→      setSelectedIndex(0);
 89→      setActionsOpen(false);
 90→      setQuickLookOpen(false);
 91→    }
 92→  }, [nav.stackDepth]);
 93→
 94→  const registrySections = useMemo(() => getSections(), []);
 95→
 96→  const filtered = useMemo(() => {
 97→    let sections = registrySections;
 98→    if (filterValue === 'commands') {
 99→      sections = sections.filter(
100→        s => s.title === 'Suggestions' || s.title === 'Commands',
101→      );
102→    } else if (filterValue === 'applications') {
103→      sections = sections.filter(s => s.title === 'Applications');
104→    }
105→
106→    const result = query ? searchCommands(query) : sections;
107→
108→    const filteredResult = query
109→      ? result
110→          .map(s => {
111→            if (filterValue === 'commands') {
112→              return s.title === 'Suggestions' || s.title === 'Commands'
113→                ? s
114→                : {
115→                    ...s,
116→                    items: [],
117→                  };
118→            }
119→            if (filterValue === 'applications') {
120→              return s.title === 'Applications'
121→                ? s
122→                : {
123→                    ...s,
124→                    items: [],
125→                  };
126→            }
127→            return s;
128→          })
129→          .filter(s => s.items.length > 0)
130→      : result;
131→
132→    const allFlatItems = registrySections.flatMap(s => s.items);
133→    const favoriteItems = favoriteIds
134→      .map(id => allFlatItems.find(item => item.id === id))
135→      .filter((item): item is ListItemData => !!item);
136→
137→    if (query) {
138→      const filteredFavs = favoriteItems.filter(
139→        item =>
140→          fuzzyMatch(query, item.title) ||
141→          fuzzyMatch(query, item.subtitle ?? ''),
142→      );
143→      if (filteredFavs.length > 0) {
144→        const favIds = new Set(filteredFavs.map(f => f.id));
145→        const dedupedSections = filteredResult
146→          .map(s => ({
147→            ...s,
148→            items: s.items.filter(item => !favIds.has(item.id)),
149→          }))
150→          .filter(s => s.items.length > 0);
151→        return [
152→          {
153→            title: 'Favorites',
154→            items: filteredFavs,
155→          },
156→          ...dedupedSections,
157→        ];
158→      }
159→      return filteredResult;
160→    }
161→
162→    const pinnedSections: SectionData[] = [];
163→    const dedupIds = new Set<string>();
164→
165→    if (favoriteItems.length > 0) {
166→      pinnedSections.push({
167→        title: 'Favorites',
168→        items: favoriteItems,
169→      });
170→      for (const item of favoriteItems) {
171→        dedupIds.add(item.id);
172→      }
173→    }
174→
175→    const favSet = new Set(favoriteIds);
176→    const recentItems = recentIds
177→      .filter(id => !favSet.has(id))
178→      .map(id => allFlatItems.find(item => item.id === id))
179→      .filter((item): item is ListItemData => !!item);
180→
181→    if (recentItems.length > 0) {
182→      pinnedSections.push({
183→        title: 'Recent Commands',
184→        items: recentItems,
185→      });
186→      for (const item of recentItems) {
187→        dedupIds.add(item.id);
188→      }
189→    }
190→
191→    if (pinnedSections.length > 0) {
192→      const dedupedSections = filteredResult
193→        .map(s => ({
194→          ...s,
195→          items: s.items.filter(item => !dedupIds.has(item.id)),
196→        }))
197→        .filter(s => s.items.length > 0);
198→      return [
199→        ...pinnedSections,
200→        ...dedupedSections,
201→      ];
202→    }
203→
204→    return filteredResult;
205→  }, [
206→    query,
207→    filterValue,
208→    favoriteIds,
209→    recentIds,
210→    registrySections,
211→  ]);
212→
213→  const calculatorResult = useMemo(() => {
214→    if (!query.trim()) return null;
215→    return evaluate(query);
216→  }, [query]);
217→
218→  const allItems = useMemo(() => {
219→    const items = flattenItems(filtered);
220→    if (calculatorResult) {
221→      const calcItem: ListItemData = {
222→        id: '__calculator__',
223→        title: `= ${calculatorResult}`,
224→        subtitle: query.trim(),
225→        icon: <CalculatorIcon />,
226→      };
227→      return [
228→        calcItem,
229→        ...items,
230→      ];
231→    }
232→    return items;
233→  }, [
234→    filtered,
235→    calculatorResult,
236→    query,
237→  ]);
238→
239→  const selectedItem = allItems[selectedIndex];
240→
241→  const handleQueryChange = useCallback((value: string) => {
242→    setQuery(value);
243→    setSelectedIndex(0);
244→    setActionsOpen(false);
245→  }, []);
246→
247→  const handleFilterChange = useCallback((value: string) => {
248→    setFilterValue(value);
249→    setSelectedIndex(0);
250→  }, []);
251→
252→  const handleActiveIndexChange = useCallback((index: number) => {
253→    setSelectedIndex(index);
254→    setActionsOpen(false);
255→  }, []);
256→
257→  const handleDrillIn = useCallback(() => {
258→    const item = allItems[selectedIndex];
259→    if (!item) return;
260→
261→    setActionsOpen(false);
262→
263→    if (item.id === '__calculator__' && calculatorResult) {
264→      performCopy(calculatorResult, showHUD, {
265→        hudIcon: <ClipboardHUDIcon />,
266→        hudTitle: `Copied ${calculatorResult}`,
267→      });
268→      return;
269→    }
270→
271→    const cmd = getCommand(item.id);
272→
273→    if (cmd?.component) {
274→      addRecent(item.id);
275→      push(cmd.name, {
276→        type: 'command',
277→        commandId: cmd.id,
278→      });
279→      setQuery('');
280→      setSelectedIndex(0);
281→    } else if (item.detail) {
282→      push(item.title, {
283→        type: 'detail',
284→        item,
285→      });
286→      setQuery('');
287→      showToast({
288→        style: 'success',
289→        title: `Opened ${item.title}`,
290→      });
291→    } else {
292→      showToast({
293→        style: 'success',
294→        title: `Opened ${item.title}`,
295→      });
296→    }
297→  }, [
298→    allItems,
299→    selectedIndex,
300→    showToast,
301→    showHUD,
302→    calculatorResult,
303→    push,
304→    addRecent,
305→  ]);
306→
307→  const toggleActions = useCallback(() => {
308→    setActionsOpen(prev => !prev);
309→  }, []);
310→
311→  const closeActions = useCallback(() => {
312→    setActionsOpen(false);
313→  }, []);
314→
315→  useKeyboardShortcut(
316→    {
317→      key: 'k',
318→      meta: true,
319→    },
320→    toggleActions,
321→  );
322→
323→  const handleToggleFavorite = useCallback(() => {
324→    if (!selectedItem || selectedItem.id === '__calculator__') {
325→      return;
326→    }
327→    const wasAlreadyFavorite = isFavorite(selectedItem.id);
328→    toggleFavorite(selectedItem.id);
329→    showHUD({
330→      icon: <StarFilledIcon />,
331→      title: wasAlreadyFavorite
332→        ? 'Removed from Favorites'
333→        : 'Added to Favorites',
334→    });
335→  }, [
336→    selectedItem,
337→    toggleFavorite,
338→    isFavorite,
339→    showHUD,
340→  ]);
341→
342→  useKeyboardShortcut(
343→    {
344→      key: 'f',
345→      meta: true,
346→      shift: true,
347→    },
348→    handleToggleFavorite,
349→    { enabled: !!selectedItem },
350→  );
351→
352→  const handleMoveFavoriteUp = useCallback(() => {
353→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
354→    moveFavorite(selectedItem.id, 'up');
355→    setSelectedIndex(prev => Math.max(0, prev - 1));
356→  }, [
357→    selectedItem,
358→    isFavorite,
359→    moveFavorite,
360→  ]);
361→
362→  const handleMoveFavoriteDown = useCallback(() => {
363→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
364→    moveFavorite(selectedItem.id, 'down');
365→    setSelectedIndex(prev => prev + 1);
366→  }, [
367→    selectedItem,
368→    isFavorite,
369→    moveFavorite,
370→  ]);
371→
372→  useKeyboardShortcut(
373→    {
374→      key: 'ArrowUp',
375→      meta: true,
376→      alt: true,
377→    },
378→    handleMoveFavoriteUp,
379→    {
380→      enabled: !!selectedItem && isFavorite(selectedItem.id),
381→    },
382→  );
383→
384→  useKeyboardShortcut(
385→    {
386→      key: 'ArrowDown',
387→      meta: true,
388→      alt: true,
389→    },
390→    handleMoveFavoriteDown,
391→    {
392→      enabled: !!selectedItem && isFavorite(selectedItem.id),
393→    },
394→  );
395→
396→  const openSettings = useCallback(() => {
397→    const settingsCmd = getCommand('settings');
398→    if (settingsCmd) {
399→      push('Settings', {
400→        type: 'command',
401→        commandId: 'settings',
402→      });
403→      setQuery('');
404→      setSelectedIndex(0);
405→      setActionsOpen(false);
406→    }
407→  }, [push]);
408→
409→  useKeyboardShortcut(
410→    {
411→      key: ',',
412→      meta: true,
413→    },
414→    openSettings,
415→  );
416→
417→  const toggleQuickLook = useCallback(() => {
418→    setQuickLookOpen(prev => !prev);
419→  }, []);
420→
421→  const closeQuickLook = useCallback(() => {
422→    setQuickLookOpen(false);
423→  }, []);
424→
425→  useKeyboardShortcut(
426→    {
427→      key: 'y',
428→      meta: true,
429→    },
430→    toggleQuickLook,
431→    { enabled: !!selectedItem?.detail },
432→  );
433→
434→  useEffect(() => {
435→    if (!selectedItem?.detail) return;
436→
437→    function handleSpaceBar(e: KeyboardEvent) {
438→      if (e.key !== ' ' || e.metaKey || e.ctrlKey || e.altKey) {
439→        return;
440→      }
441→      if (query !== '') return;
442→
443→      e.preventDefault();
444→      e.stopPropagation();
445→      setQuickLookOpen(prev => !prev);
446→    }
447→
448→    window.addEventListener('keydown', handleSpaceBar);
449→    return () => window.removeEventListener('keydown', handleSpaceBar);
450→  }, [
451→    selectedItem?.detail,
452→    query,
453→  ]);
454→
455→  const isCalculatorSelected = selectedItem?.id === '__calculator__';
456→  const detail = isCalculatorSelected ? undefined : selectedItem?.detail;
457→
458→  const dropdownSections = useMemo(
459→    () => [
460→      {
461→        title: 'Primary Actions',
462→        actions: [
463→          isCalculatorSelected && calculatorResult
464→            ? createCopyAction(
465→                {
466→                  content: calculatorResult,
467→                  title: 'Copy Result',
468→                  shortcut: <Kbd keys={['↵']} />,
469→                  hudIcon: <ClipboardHUDIcon />,
470→                  hudTitle: `Copied ${calculatorResult}`,
471→                },
472→                showHUD,
473→              )
474→            : {
475→                label: 'Open',
476→                shortcut: <Kbd keys={['↵']} />,
477→                onClick: () => {
478→                  if (selectedItem) {
479→                    showToast({
480→                      style: 'success' as const,
481→                      title: `Opened ${selectedItem.title}`,
482→                    });
483→                  }
484→                },
485→              },
486→          {
487→            label: 'Quick Look',
488→            shortcut: (
489→              <Kbd
490→                keys={[
491→                  '⌘',
492→                  'Y',
493→                ]}
494→              />
495→            ),
496→            onClick: () => {
497→              if (selectedItem?.detail) {
498→                setActionsOpen(false);
499→                setQuickLookOpen(prev => !prev);
500→              }
501→            },
502→          },
503→          ...(!isCalculatorSelected && selectedItem
504→            ? [
505→                {
506→                  label:
507→                    selectedItem && isFavorite(selectedItem.id)
508→                      ? 'Remove from Favorites'
509→                      : 'Add to Favorites',
510→                  shortcut: (
511→                    <Kbd
512→                      keys={[
513→                        '⌘',
514→                        '⇧',
515→                        'F',
516→                      ]}
517→                    />
518→                  ),
519→                  onClick: () => {
520→                    if (selectedItem) {
521→                      setActionsOpen(false);
522→                      handleToggleFavorite();
523→                    }
524→                  },
525→                },
526→              ]
527→            : []),
528→        ],
529→      },
530→      {
531→        title: 'Copy Actions',
532→        actions: [
533→          createCopyAction(
534→            {
535→              content: selectedItem?.title ?? '',
536→              title: 'Copy Name',
537→              shortcut: (
538→                <Kbd
539→                  keys={[
540→                    '⌘',
541→                    'C',
542→                  ]}
543→                />
544→              ),
545→            },
546→            showHUD,
547→          ),
548→          {
549→            label: 'Copy As...',
550→            submenu: [
551→              {
552→                actions: [
553→                  createCopyAction(
554→                    {
555→                      content: `**${selectedItem?.title ?? ''}**${selectedItem?.subtitle ? ` — ${selectedItem.subtitle}` : ''}`,
556→                      title: 'Copy as Markdown',
557→                      hudTitle: 'Copied as Markdown',
558→                    },
559→                    showHUD,
560→                  ),
561→                  createCopyAction(
562→                    {
563→                      content: JSON.stringify({
564→                        title: selectedItem?.title,
565→                        subtitle: selectedItem?.subtitle,
566→                      }),
567→                      title: 'Copy as JSON',
568→                      hudTitle: 'Copied as JSON',
569→                    },
570→                    showHUD,
571→                  ),
572→                  createCopyAction(
573→                    {
574→                      content: selectedItem?.title ?? '',
575→                      title: 'Copy as Plain Text',
576→                      hudTitle: 'Copied as Plain Text',
577→                    },
578→                    showHUD,
579→                  ),
580→                ],
581→              },
582→            ],
583→          },
584→        ],
