type NavViewData =
  | {
      type: 'command';
      commandId: string;
    }
  | {
      type: 'detail';
      item: ListItemData;
    };

const TRAY_COMMAND_MAP: Record<
  string,
  {
    id: string;
    name: string;
  }
> = {
  clipboard: {
    id: 'clipboard-history',
    name: 'Clipboard History',
  },
  snippets: {
    id: 'snippets',
    name: 'Snippets',
  },
  settings: {
    id: 'settings',
    name: 'Settings',
  },
  about: {
    id: 'settings',
    name: 'Settings',
  },
  'check-updates': {
    id: 'settings',
    name: 'Settings',
  },
};

function flattenItems(sections: SectionData[]): ListItemData[] {
  return sections.flatMap(s => s.items);
}

function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  switch (entry.type) {
    case 'label':
      return (
        <DetailMetadata.Label
          key={index}
          title={entry.title}
          text={entry.text}
        />
      );
    case 'link':
      return (
        <DetailMetadata.Link
          key={index}
          title={entry.title}
          text={entry.text}
          target={entry.target}
        />
      );
    case 'tag-list':
      return (
        <DetailMetadata.TagList key={index} title={entry.title}>
          {entry.tags.map(tag => (
            <DetailMetadata.Tag
              key={tag.text}
              text={tag.text}
              color={tag.color}
            />
          ))}
        </DetailMetadata.TagList>
      );
    case 'separator':
      return <DetailMetadata.Separator key={index} />;
  }
}

function SearchIcon() {
  return (
